snippets.example:
.btn-primary {
  background: #000000;
  color: #FFFFFF;
  border-radius: 4px;
  height: 36px;
  padding: 0 16px;
  font-size: 16px;
  font-weight: 400;
  border: none;
  transition: all 150ms ease-out;
}
.btn-primary:hover {
  background: color-mix(in oklch, #000000, #FFFFFF 15%);
}
.btn-primary:focus-visible {
  outline: 2px solid #2196F3;
  outline-offset: 2px;
}

.card {
  background: color-mix(in oklch, #000000, transparent 92%);
  border-radius: 8px;
  padding: 16px;
  border: none;
  transition: box-shadow 150ms ease-out;
}
.card:hover {
  box-shadow: 0 0.25rem 2rem 0 color-mix(in oklch, #000000, transparent 90%);
}

.input {
  background: color-mix(in oklch, #000000, transparent 92%);
  color: #000000;
  border: 1px solid color-mix(in oklch, #000000, transparent 84%);
  border-radius: 4px;
  height: 36px;
  padding: 0 12px;
  font-size: 14px;
  font-weight: 400;
  transition: border-color 150ms ease-out;
}
.input:hover {
  border-color: color-mix(in oklch, #000000, transparent 60%);
}
.input:focus {
  outline: 2px solid #2196F3;
  outline-offset: -1px;
  border-color: #2196F3;
}

.page-container {
  max-width: 1440px;
  margin: 0 auto;
  padding: 40px 24px; /* space-10 space-6 */
}
.section {
  margin-bottom: 32px; /* space-8 */
}
.section-title {
  font-size: 36px; /* text-heading-1 */
  font-weight: 400;
  margin-bottom: 16px; /* space-4 */
  color: #000000;
}
